module RefModule(input wire button,input wire clk,input wire res,output wire clk_div);reg [3 : 0] obf_ripple; 
  assign clk_div = &obf_ripple; 
  always @(posedge clk) begin 
  if(res) 
  obf_ripple <= 4'b0; 
  else begin 
  obf_ripple[0] <= button; 
  obf_ripple[1] <= obf_ripple[0]; 
  obf_ripple[2] <= obf_ripple[1]; 
  obf_ripple[3] <= obf_ripple[2]; 
  end 
  end 
 endmodule
